/** Top-level (root) categories only. */
export const QUEBEC_ROOT_CATEGORIES = QUEBEC_CATEGORIES.filter((c) => !c.parentSlug);

/** Map root slug -> direct children. */
export function childrenOf(rootSlug: string): QuebecCategorySeed[] {
  return QUEBEC_CATEGORIES.filter((c) => c.parentSlug === rootSlug);
}
